/**
 * Simple async mutex for serializing access to shared resources.
 * Uses a promise-chain pattern - no deadlock risk with fair scheduling.
 */
class AsyncMutex {
    private current = Promise.resolve();
    private release: (() => void) | null = null;

    /**
     * Execute a function exclusively under this mutex.
     * The mutex is released in a finally block after the function completes or throws.
     */
    async runExclusive<T>(fn: () => Promise<T>): Promise<T> {
        await this.current;
        this.current = new Promise<void>((resolve) => {
            this.release = resolve;
        });
        try {
            return await fn();
        } finally {
            this.release?.();
            this.release = null;
        }
    }
}
```

